const PaymentModule = () => {
  const [loading, setLoading] = useState(false);
  const [integrityResult, setIntegrityResult] = useState(null);
  const [products, setProducts] = useState([]);
  const [securityStatus, setSecurityStatus] = useState('checking');

  useEffect(() => {
    initializePaymentModule();

    return () => {
      InAppPurchaseManager.cleanup();
    };
  }, []);

  const initializePaymentModule = async () => {
    try {
      setLoading(true);

      const integrity = await DeviceIntegrityChecker.performComprehensiveCheck();
      setIntegrityResult(integrity);

      if (integrity.isCompromised) {
        setSecurityStatus('compromised');
        Alert.alert(
          'Security Warning',
          'Your device appears to be compromised. Payment features are restricted for your protection.',
          [{ text: 'OK' }]
        );
        return;
      }

      if (integrity.riskLevel === 'HIGH' || integrity.riskLevel === 'CRITICAL') {
        setSecurityStatus('high-risk');
        Alert.alert(
          'Security Notice',
          'Additional security measures will be required for transactions.',
          [{ text: 'OK' }]
        );
      } else {
        setSecurityStatus('secure');
      }

      const availableProducts = await InAppPurchaseManager.initialize();
      setProducts(availableProducts);
    } catch (error) {
      console.error('Initialization error:', error);
      Alert.alert('Error', 'Failed to initialize payment module');
    } finally {
      setLoading(false);
    }
  };

  const handleInAppPurchase = async (productId) => {
    if (!integrityResult || integrityResult.isCompromised) {
      Alert.alert('Error', 'Payment not allowed due to security concerns');
      return;
    }

    try {
      setLoading(true);

      const result = await InAppPurchaseManager.purchaseProduct(
        productId,
        integrityResult
      );

      Alert.alert('Success', 'Purchase completed successfully!');
    } catch (error) {
      if (error.message === 'PAYMENT_BLOCKED_SECURITY') {
        Alert.alert('Security Error', 'Payment blocked for security reasons');
      } else if (error.message === 'USER_CANCELLED_VERIFICATION') {
        Alert.alert('Cancelled', 'Payment verification cancelled');
      } else {
        Alert.alert('Error', 'Purchase failed. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleDigitalWalletPayment = async (provider, amount, currency) => {
    if (!integrityResult || integrityResult.isCompromised) {
      Alert.alert('Error', 'Payment not allowed due to security concerns');
      return;
    }

    try {
      setLoading(true);

      const paymentData = {
        amount,
        currency,
        productId: 'digital_wallet_payment',
      };

      let result;
      switch (provider) {
        case PAYMENT_PROVIDERS.STRIPE:
          result = await DigitalWalletManager.processStripePayment(
            paymentData,
            integrityResult
          );
          break;
        case PAYMENT_PROVIDERS.APPLE_PAY:
          result = await DigitalWalletManager.processApplePay(
            paymentData,
            integrityResult
          );
          break;
        case PAYMENT_PROVIDERS.GOOGLE_PAY:
          result = await DigitalWalletManager.processGooglePay(
            paymentData,
            integrityResult
          );
          break;
        default:
          throw new Error('UNSUPPORTED_PROVIDER');
      }

      Alert.alert('Success', 'Payment processed successfully!');
    } catch (error) {
      if (error.message === 'PAYMENT_BLOCKED_SECURITY') {
        Alert.alert('Security Error', 'Payment blocked for security reasons');
      } else {
        Alert.alert('Error', 'Payment failed. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleRestorePurchases = async () => {
    if (!integrityResult || integrityResult.isCompromised) {
      Alert.alert('Error', 'Restore not allowed due to security concerns');
      return;
    }

    try {
      setLoading(true);
      const purchases = await InAppPurchaseManager.restorePurchases(integrityResult);
      Alert.alert('Success', `Restored ${purchases.length} purchase(s)`);
    } catch (error) {
      Alert.alert('Error', 'Failed to restore purchases');
    } finally {
      setLoading(false);
    }
  };

  const getSecurityStatusColor = () => {
    switch (securityStatus) {
      case 'secure':
        return '#4CAF50';
      case 'high-risk':
        return '#FF9800';
      case 'compromised':
        return '#F44336';
      default:
        return '#9E9E9E';
    }
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Processing...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={styles.securityBanner}>
        <View
          style={[
            styles.securityIndicator,
            { backgroundColor: getSecurityStatusColor() },
          ]}
        />
        <Text style={styles.securityText}>
          Security Status: {securityStatus.toUpperCase()}
        </Text>
        {integrityResult && (
          <Text style={styles.securityScore}>
            Integrity Score: {integrityResult.integrityScore}/100
          </Text>
        )}
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>In-App Purchases</Text>
        {products.map((product) => (
          <TouchableOpacity
            key={product.productId}
            style={[
              styles.button,
              integrityResult?.isCompromised && styles.buttonDisabled,
            ]}
            onPress={() => handleInAppPurchase(product.productId)}
            disabled={integrityResult?.isCompromised}
          >
            <Text style={styles.buttonText}>
              {product.title} - {product.localizedPrice}
            </Text>
          </TouchableOpacity>
        ))}

        <TouchableOpacity
          style={[
            styles.button,
            styles.secondaryButton,
            integrityResult?.isCompromised && styles.buttonDisabled,
          ]}
          onPress={handleRestorePurchases}
          disabled={integrityResult?.isCompromised}
        >
          <Text style={styles.buttonText}>Restore Purchases</Text>
        </TouchableOpacity>
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Digital Wallet</Text>
        
        <TouchableOpacity
          style={[
            styles.button,
            integrityResult?.isCompromised && styles.buttonDisabled,
          ]}
          onPress={() =>
            handleDigitalWalletPayment(PAYMENT_PROVIDERS.STRIPE, 9.99, 'USD')
          }
          disabled={integrityResult?.isCompromised}
        >
          <Text style={styles.buttonText}>Pay with Stripe ($9.99)</Text>
        </TouchableOpacity>

        {Platform.OS === 'ios' && (
          <TouchableOpacity
            style={[
              styles.button,
              integrityResult?.isCompromised && styles.buttonDisabled,
            ]}
            onPress={() =>
              handleDigitalWalletPayment(PAYMENT_PROVIDERS.APPLE_PAY, 9.99, 'USD')
            }
            disabled={integrityResult?.isCompromised}
          >
            <Text style={styles.buttonText}>Pay with Apple Pay ($9.99)</Text>
          </TouchableOpacity>
        )}

        {Platform.OS === 'android' && (
          <TouchableOpacity
            style={[
              styles.button,
              integrityResult?.isCompromised && styles.buttonDisabled,
            ]}
            onPress={() =>
              handleDigitalWalletPayment(PAYMENT_PROVIDERS.GOOGLE_PAY, 9.99, 'USD')
            }
            disabled={integrityResult?.isCompromised}
          >
            <Text style={styles.buttonText}>Pay with Google Pay ($9.99)</Text>
          </TouchableOpacity>
        )}
      </View>

      {integrityResult?.isCompromised && (
        <View style={styles.warningBanner}>
          <Text style={styles.warningText}>
            ⚠️ Payment features are disabled due to security concerns
          </Text>
        </View>
      )}
    </View>
  );
};

